mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT p.PAGE_ID AS pageId, p.PAGE_NAME AS pageName, p.CREATE_USER_NAME AS createUserName,
CASE WHEN lh.FILE_ID IS NOT NULL THEN si.INSTANCE_IP END AS instanceIp, CASE WHEN lh.FILE_ID IS NOT NULL THEN si.INSTANCE_PORT END AS instancePort FROM SPW_CMS_PAGE p LEFT JOIN ( SELECT REGEXP_REPLACE(FILE_ID, '_v\d+\.html$', '') AS PAGE_ID, FILE_ID, INSTANCE_ID, ROW_NUMBER() OVER ( PARTITION BY REGEXP_REPLACE(FILE_ID, '_v\d+\.html$', '') ORDER BY LAST_MODIFIED_DTIME DESC ) AS RN FROM FWK_CMS_FILE_SEND_HIS WHERE FILE_ID LIKE '%_v%.html' ) lh ON lh.PAGE_ID = p.PAGE_ID AND lh.RN = 1 LEFT JOIN FWK_CMS_SERVER_INSTANCE si ON lh.INSTANCE_ID = si.INSTANCE_ID
ORDER BY p.LAST_MODIFIED_DTIME DESC NULLS LAST ) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
